# === formatting.py ===
"""Text and paragraph formatting helpers for python-pptx shapes."""

from pptx.dml.color import RGBColor
from pptx.enum.text import PP_ALIGN
from pptx.oxml.xmlchemy import OxmlElement
from pptx.util import Pt


def clear_bullets(paragraph):
    """Remove bullet formatting from a paragraph."""

    pPr = paragraph._p.get_or_add_pPr()
    bu_none = OxmlElement("a:buNone")
    # Remove existing bullet children then insert buNone
    for child in list(pPr):
        if child.tag.endswith("buNone") or child.tag.endswith("buFont") or child.tag.endswith("buChar"):
            pPr.remove(child)
    pPr.insert(0, bu_none)


def apply_paragraph_formatting(paragraph, config):
    """Apply paragraph-level formatting.

    Config keys (all optional unless specified):
      - bullet (bool): enable bullets. If False/absent bullets are cleared.
      - level (int): indent level, required when bullet is True.
      - alignment (str): "LEFT", "CENTER", "RIGHT", "JUSTIFY".
      - space_before (float): points
      - space_after (float): points
      - line_spacing (float): points

    Example::

        apply_paragraph_formatting(paragraph, {"bullet": False, "alignment": "LEFT"})
    """

    bullet = config.get("bullet")
    if bullet:
        paragraph.level = config.get("level", 0)
    else:
        clear_bullets(paragraph)

    alignment = config.get("alignment")
    if alignment:
        paragraph.alignment = getattr(PP_ALIGN, alignment.upper(), None)

    if "space_before" in config:
        paragraph.space_before = Pt(config["space_before"])
    if "space_after" in config:
        paragraph.space_after = Pt(config["space_after"])
    if "line_spacing" in config:
        paragraph.line_spacing = Pt(config["line_spacing"])


def apply_text_formatting(run, config):
    """Apply run-level formatting.

    Config keys (all optional):
      - font_name (str)
      - font_size (float, points)
      - bold (bool)
      - italic (bool)
      - underline (bool)
      - color (str): hex RGB (e.g., "00338D")

    Example::

        apply_text_formatting(run, {"font_name": "Arial", "font_size": 12, "bold": True, "color": "00338D"})
    """

    font = run.font

    if "font_name" in config:
        font.name = config["font_name"]
    if "font_size" in config:
        font.size = Pt(config["font_size"])
    if "bold" in config:
        font.bold = bool(config["bold"])
    if "italic" in config:
        font.italic = bool(config["italic"])
    if "underline" in config:
        font.underline = bool(config["underline"])

    color = config.get("color")
    if color:
        color = color.lstrip("#")
        rgb = RGBColor.from_string(color)
        font.color.rgb = rgb


__all__ = ["clear_bullets", "apply_paragraph_formatting", "apply_text_formatting"]


# === rearrange.py ===
"""Slide duplication utilities for KPMG-PPTX.

The duplicate_slide function performs a deep copy of a slide while
preserving image and other relationships. It is a focused port of the
proven logic used in the document-skills toolkit, trimmed to the
minimal surface we need for template cloning.
"""

from copy import deepcopy
from pptx.opc.constants import RELATIONSHIP_TYPE as RT

REL_NS = "http://schemas.openxmlformats.org/officeDocument/2006/relationships"
REL_PREFIX = f"{{{REL_NS}}}"


def _clone_relationships(src_part, dest_part):
    """Copy relationships from ``src_part`` to ``dest_part``.

    Returns a mapping of old relationship IDs to the newly created IDs so
    we can update embedded references (e.g., ``r:embed`` on blips).

    Some python-pptx versions implement ``_Relationships.values()`` via
    ``[self[k] for k in self]`` while ``__iter__`` yields relationship
    objects, not rId strings, which triggers a KeyError lookup. To avoid
    that, prefer the underlying ``_rels`` dict when available.
    """

    rel_id_map: dict[str, str] = {}

    rels_collection = src_part.rels
    raw_rels = getattr(rels_collection, "_rels", None)

    # Prefer the plain dict to avoid Mapping.values() relying on buggy __iter__
    if raw_rels is not None:
        rels_iter = list(raw_rels.values())
    else:
        # Fallback for future python-pptx versions
        rels_iter = list(rels_collection)

    # Force resolution of all relationships up front to avoid lazy-load bugs
    for rel in rels_iter:
        # Skip notesSlide/slide master rels; python-pptx manages them
        if rel.reltype in {RT.SLIDE_MASTER, RT.NOTES_SLIDE, RT.SLIDE_LAYOUT}:
            continue

        old_rid = rel.rId
        new_rid = dest_part.rels._add_relationship(rel.reltype, rel._target, rel.is_external)
        rel_id_map[old_rid] = new_rid

    return rel_id_map


def _remap_blip_rels(element, rel_id_map):
    """Update all ``a:blip`` embed references in ``element`` using ``rel_id_map``."""

    nsmap = {
        "a": "http://schemas.openxmlformats.org/drawingml/2006/main",
        "r": "http://schemas.openxmlformats.org/officeDocument/2006/relationships",
    }

    for blip in element.iterfind('.//a:blip', namespaces=nsmap):
        embed = blip.get(f"{{{nsmap['r']}}}embed")
        if embed and embed in rel_id_map:
            blip.set(f"{{{nsmap['r']}}}embed", rel_id_map[embed])


def _remap_relationship_ids(element, rel_id_map):
    """Update any r:* attributes in ``element`` using ``rel_id_map``.

    This catches embeds, hyperlinks, OLE objects, and any other relationship-
    backed references that appear on shapes. Without this, duplicated slides
    can retain stale relationship IDs when the newly created relationships use
    different identifiers (common in real-world templates with non-contiguous
    rIds), which leads to missing-relationship errors on save.
    """

    if not rel_id_map:
        return

    for el in element.iter():
        for attr, val in list(el.attrib.items()):
            if attr.startswith(REL_PREFIX) and val in rel_id_map:
                el.attrib[attr] = rel_id_map[val]


def duplicate_slide(presentation, slide_index):
    """Duplicate a slide in ``presentation`` and return the new slide.

    This deep-copies the slide XML, preserves ordering, and recreates the
    embedded image/chart relationships so copied shapes continue to
    display correctly.

    Args:
        presentation: python-pptx ``Presentation`` instance.
        slide_index: int, zero-based index of the slide to duplicate.

    Returns:
        The newly created slide object (appended to the presentation).
    """

    src = presentation.slides[slide_index]
    dest = presentation.slides.add_slide(src.slide_layout)

    # Remove all auto-generated placeholders from the new slide
    # This prevents "double shapes" (one from layout, one copied from source)
    for shape in list(dest.shapes):
        dest.shapes._spTree.remove(shape.element)

    # Copy relationships first so we can remap embeds when cloning shapes
    rel_id_map = _clone_relationships(src.part, dest.part)

    # Deep-copy every shape (maintain original ordering)
    for shape in src.shapes:
        new_el = deepcopy(shape.element)
        _remap_relationship_ids(new_el, rel_id_map)
        dest.shapes._spTree.insert_element_before(new_el, 'p:extLst')

    return dest


def delete_slide(presentation, index: int) -> None:
    """Delete slide at given index from presentation.

    Args:
        presentation: python-pptx Presentation instance
        index: Zero-based slide index to delete

    Raises:
        IndexError: If index is out of range
    """
    if index < 0 or index >= len(presentation.slides):
        raise IndexError(f"Slide index {index} out of range (0-{len(presentation.slides)-1})")

    rId = presentation.slides._sldIdLst[index].rId
    presentation.part.drop_rel(rId)
    del presentation.slides._sldIdLst[index]


__all__ = ["duplicate_slide", "delete_slide"]


# === pagination.py ===
"""Pagination utilities for glossary and slide content.

This module provides height-based estimation for packing glossary items
into slides with adaptive row heights. Each column has a pixel height
budget, and items are packed until the budget is exhausted.

Python 3.9+ compatible.
"""

from typing import Any, Dict, List, Tuple, Union

# Calibration values for KPMG glossary template (measured from template)
GLOSSARY_PAGINATION_DEFAULTS = {
    # Column dimensions
    'col_width_pt': 276,            # Definition column width in points
    'font_size_pt': 10,             # Font size in points (matches glossary formatting)

    # Table dimensions
    'left_table_height_pt': 416.9,  # Left table total height
    'right_table_height_pt': 438.5, # Right table total height
    'header_height_pt': 21.3,       # Header row height
    'left_max_rows': 17,            # Max data rows in left table
    'right_max_rows': 18,           # Max data rows in right table

    # Text metrics
    'char_width_multiplier': 0.55,  # char_width = font_size * this
    'line_height_multiplier': 1.2,  # line_height = font_size * this
    'row_padding_pt': 4,            # Extra padding per row
    'min_row_height_pt': 15,        # Minimum row height
}


def _estimate_item_height_pt(
    definition: str,
    col_width_pt: float = GLOSSARY_PAGINATION_DEFAULTS['col_width_pt'],
    font_size_pt: float = GLOSSARY_PAGINATION_DEFAULTS['font_size_pt'],
) -> float:
    """Estimate row height in points needed to display a definition.

    Args:
        definition: The definition text.
        col_width_pt: Column width in points.
        font_size_pt: Font size in points.

    Returns:
        Estimated height in points needed to display the text.
    """
    if not definition:
        return GLOSSARY_PAGINATION_DEFAULTS['min_row_height_pt']

    char_width = font_size_pt * GLOSSARY_PAGINATION_DEFAULTS['char_width_multiplier']
    chars_per_line = int(col_width_pt / char_width)
    lines = max(1, -(-len(definition) // chars_per_line))  # Ceiling division

    line_height = font_size_pt * GLOSSARY_PAGINATION_DEFAULTS['line_height_multiplier']
    height = lines * line_height + GLOSSARY_PAGINATION_DEFAULTS['row_padding_pt']

    return max(height, GLOSSARY_PAGINATION_DEFAULTS['min_row_height_pt'])


def _extract_term_def(item) -> Tuple[str, str]:
    """Extract term and definition from item, supporting dict or tuple format."""
    if isinstance(item, dict):
        return item.get('term', ''), item.get('definition', '')
    elif isinstance(item, (list, tuple)) and len(item) >= 2:
        return str(item[0]), str(item[1])
    return '', ''


def _pack_column(
    items: List[Any],
    available_height_pt: float,
    max_rows: int = None,
) -> Tuple[List[Tuple[Any, float]], float]:
    """Pack items into a column until height budget or row limit is exhausted.

    Args:
        items: List of items to pack (will not be modified).
        available_height_pt: Height budget in points.
        max_rows: Maximum number of rows (items) allowed in this column.

    Returns:
        Tuple of (list of (item, height) pairs, total height used).
    """
    packed = []
    used_height = 0.0

    for item in items:
        # Check row limit
        if max_rows is not None and len(packed) >= max_rows:
            break

        _, definition = _extract_term_def(item)
        height = _estimate_item_height_pt(definition)

        if used_height + height <= available_height_pt:
            packed.append((item, height))
            used_height += height
        else:
            break

    return packed, used_height


def paginate_glossary_items(
    items: List[Dict[str, Any]],
    left_table_height_pt: float = None,
    right_table_height_pt: float = None,
) -> List[Dict[str, List[Tuple[Any, float]]]]:
    """Split glossary items across pages using height-based column packing.

    Uses pixel height budgets per column to pack items. Each item's row
    height is estimated based on definition length, allowing adaptive
    row heights that ensure all text is visible.

    Args:
        items: List of {'term': str, 'definition': str} dicts or (term, def) tuples.
        left_table_height_pt: Height budget for left column (default from template).
        right_table_height_pt: Height budget for right column (default from template).

    Returns:
        List of pages, where each page is a dict with 'left' and 'right' keys,
        each containing a list of (item, height_pt) tuples.

    Example:
        >>> items = [{'term': 'API', 'definition': 'Application Programming Interface'}]
        >>> pages = paginate_glossary_items(items)
        >>> len(pages)
        1
        >>> len(pages[0]['left']) + len(pages[0]['right'])
        1
    """
    if not items:
        return []

    # Use defaults if not specified
    if left_table_height_pt is None:
        left_table_height_pt = (
            GLOSSARY_PAGINATION_DEFAULTS['left_table_height_pt']
            - GLOSSARY_PAGINATION_DEFAULTS['header_height_pt']
        )
    if right_table_height_pt is None:
        right_table_height_pt = (
            GLOSSARY_PAGINATION_DEFAULTS['right_table_height_pt']
            - GLOSSARY_PAGINATION_DEFAULTS['header_height_pt']
        )

    left_max_rows = GLOSSARY_PAGINATION_DEFAULTS['left_max_rows']
    right_max_rows = GLOSSARY_PAGINATION_DEFAULTS['right_max_rows']

    pages: List[Dict[str, List[Tuple[Any, float]]]] = []
    remaining = list(items)

    while remaining:
        # Pack left column (respecting both height and row limits)
        left_packed, _ = _pack_column(remaining, left_table_height_pt, left_max_rows)
        remaining = remaining[len(left_packed):]

        # Pack right column (respecting both height and row limits)
        right_packed, _ = _pack_column(remaining, right_table_height_pt, right_max_rows)
        remaining = remaining[len(right_packed):]

        # Handle edge case: item too tall for column (force it)
        if not left_packed and not right_packed and remaining:
            item = remaining.pop(0)
            _, definition = _extract_term_def(item)
            height = _estimate_item_height_pt(definition)
            left_packed = [(item, height)]

        if left_packed or right_packed:
            pages.append({
                'left': left_packed,
                'right': right_packed,
            })

    return pages


# Legacy function for backwards compatibility with tests
def _estimate_item_rows(
    term: str,
    definition: str,
    chars_per_line: int = 55,
    term_chars_per_line: int = 20,
) -> int:
    """Legacy: Estimate rows needed (for backwards compatibility).

    Note: This function is deprecated. Use _estimate_item_height_pt instead.
    """
    term_lines = max(1, -(-len(term) // term_chars_per_line))
    definition_lines = max(1, -(-len(definition) // chars_per_line))
    return max(term_lines, definition_lines)


# === glossary_generator.py ===
"""Generate KPMG-branded glossary slides from JSON input."""

import argparse
import json
import sys
from pathlib import Path
from typing import Sequence, TypedDict, Union

# Add parent directory to path for imports

from pptx import Presentation
from pptx.enum.shapes import MSO_SHAPE_TYPE
from pptx.util import Pt


TERM_FORMAT = {"font_name": "Arial", "font_size": 10, "bold": True, "color": "00338D"}
DEFINITION_FORMAT = {"font_name": "Arial", "font_size": 10, "bold": False, "color": "000000"}
PARAGRAPH_FORMAT = {"bullet": False, "alignment": "LEFT"}


def _extract_term_definition(item):
    """Extract term and definition from item, supporting dict or tuple format."""
    if isinstance(item, dict):
        return item.get("term", ""), item.get("definition", "")
    elif isinstance(item, (list, tuple)) and len(item) >= 2:
        return str(item[0]), str(item[1])
    return "", ""


class GlossaryItem(TypedDict):
    term: str
    definition: str


def _find_tables(slide):
    return [shape.table for shape in slide.shapes if shape.shape_type == MSO_SHAPE_TYPE.TABLE]


def _validate_tables(slide):
    tables = _find_tables(slide)
    if len(tables) < 2:
        raise ValueError(f"Template must contain at least 2 tables; found {len(tables)}.")

    for idx, table in enumerate(tables[:2], start=1):
        if len(table.columns) < 2:
            raise ValueError(f"Table {idx} must have at least 2 columns.")

    return tables


def _format_cell(cell, text, text_cfg):
    cell.text = text
    for paragraph in cell.text_frame.paragraphs:
        clear_bullets(paragraph)
        apply_paragraph_formatting(paragraph, PARAGRAPH_FORMAT)
        for run in paragraph.runs:
            apply_text_formatting(run, text_cfg)


def _clear_rows(table, start_row):
    for row_idx in range(start_row, len(table.rows)):
        for col in range(len(table.columns)):
            _format_cell(table.cell(row_idx, col), "", DEFINITION_FORMAT)


def _load_items(input_data: str):
    if input_data.endswith(".json") and Path(input_data).exists():
        with open(input_data, "r") as f:
            items = json.load(f)
    else:
        try:
            items = json.loads(input_data)
        except json.JSONDecodeError as exc:
            raise ValueError("Input must be a valid JSON string or path to JSON file.") from exc

    if not isinstance(items, list):
        raise ValueError("Input must be a list of dictionaries.")

    for idx, item in enumerate(items):
        if not isinstance(item, dict):
            raise ValueError(f"Item {idx} is not a dictionary.")

    return items


def _fill_slide(slide, page_data):
    """Fill a slide with glossary items using adaptive row heights.

    Args:
        slide: The slide to fill.
        page_data: Dict with 'left' and 'right' keys, each containing
            a list of (item, height_pt) tuples from pagination.
    """
    tables = _validate_tables(slide)

    left_table, right_table = tables[0], tables[1]
    left_items = page_data.get('left', [])
    right_items = page_data.get('right', [])

    # Fill left table with adaptive row heights
    for idx, (item, height_pt) in enumerate(left_items, start=1):
        term, definition = _extract_term_definition(item)
        left_table.rows[idx].height = Pt(height_pt)
        _format_cell(left_table.cell(idx, 0), term, TERM_FORMAT)
        _format_cell(left_table.cell(idx, 1), definition, DEFINITION_FORMAT)
    _clear_rows(left_table, len(left_items) + 1)

    # Fill right table with adaptive row heights
    for idx, (item, height_pt) in enumerate(right_items, start=1):
        term, definition = _extract_term_definition(item)
        right_table.rows[idx].height = Pt(height_pt)
        _format_cell(right_table.cell(idx, 0), term, TERM_FORMAT)
        _format_cell(right_table.cell(idx, 1), definition, DEFINITION_FORMAT)
    _clear_rows(right_table, len(right_items) + 1)


def generate_glossary(
    template_path: Union[Path, str],
    items: Sequence[GlossaryItem],
    output_path: Union[Path, str],
) -> Path:
    """Fill the glossary template; duplicate slides when capacity is exceeded.

    Uses dynamic pagination based on estimated text height to avoid overflow.

    Args:
        template_path: Path to the glossary template PPTX file.
        items: Sequence of glossary items. Each item can be:
            - dict with 'term' and 'definition' keys
            - tuple/list of (term, definition)
        output_path: Path where the generated PPTX will be saved.

    Returns:
        Path to the generated output file.

    Note:
        If items is empty, creates an output file with a single empty glossary
        slide (the template slide with cleared tables).
    """
    template_path = Path(template_path)
    output_path = Path(output_path)

    prs = Presentation(str(template_path))
    base_index = 0

    first_slide = prs.slides[base_index]
    tables = _validate_tables(first_slide)

    left_cap = len(tables[0].rows) - 1
    right_cap = len(tables[1].rows) - 1
    if left_cap <= 0 or right_cap <= 0:
        raise ValueError("Template tables have no available rows for glossary entries.")

    # Handle empty input explicitly: create one empty slide
    if not items:
        _fill_slide(first_slide, {'left': [], 'right': []})
        prs.save(str(output_path))
        print(f"Generated empty glossary (0 terms, 1 slide) at {output_path}")
        return output_path

    # Use height-based pagination for adaptive row heights
    pages = paginate_glossary_items(list(items))

    print(f"Paginated {len(items)} terms into {len(pages)} slide(s)")

    for page_idx, page_data in enumerate(pages):
        target_slide = first_slide if page_idx == 0 else duplicate_slide(prs, base_index)
        _fill_slide(target_slide, page_data)

    prs.save(str(output_path))
    print(f"Generated glossary with {len(items)} terms across {len(pages)} slide(s) at {output_path}")
    return output_path


def main():
    parser = argparse.ArgumentParser(description="Generate KPMG Glossary Slides")
    parser.add_argument("--template", required=True, help="Path to template PPTX")
    parser.add_argument("--input", required=True, help="JSON string or file path with terms")
    parser.add_argument("--output", required=True, help="Output PPTX path")

    args = parser.parse_args()

    try:
        items = _load_items(args.input)
        generate_glossary(args.template, items, args.output)
    except Exception as exc:  # pragma: no cover - surfaced to user
        print(str(exc), file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()

